/** A single row of chart data: keys are field names, values are numbers or category labels. */
export type Datum = Record<string, string | number>;

/** Inner padding between the SVG edge and the plotting area. */
export interface Margin {
  top: number;
  right: number;
  bottom: number;
  left: number;
}

/** Per-series visual config. `color` is a CSS color or token, e.g. 'var(--chart-1)'. */
export interface SeriesConfigEntry {
  label: string;
  color: string;
  /** Formatter preset name, e.g. 'currency:BRL' | 'percent' | 'compact'. */
  format?: string;
}

/** Maps a data field name to its series config. JSON-serializable (generative-UI ready). */
export type ChartConfig = Record<string, SeriesConfigEntry>;

export const DEFAULT_MARGIN: Margin = { top: 8, right: 8, bottom: 24, left: 40 };

import { format as d3Format } from "d3-format";

const number = d3Format(",");
const compact = d3Format(".3~s");
const percent = d3Format(".1~%");

/**
 * Format a numeric value using a named preset. Presets are JSON-friendly
 * strings (no functions) so the styled layer's config stays serializable
 * for generative UI. Unknown presets fall back to the default number format.
 *
 * Supported: 'number' (default) | 'currency:<ISO>' | 'percent' | 'compact'.
 */
export function formatValue(value: number, preset = "number"): string {
  if (preset.startsWith("currency:")) {
    const currency = preset.slice("currency:".length) || "USD";
    return new Intl.NumberFormat("en-US", { style: "currency", currency }).format(
      value
    );
  }
  switch (preset) {
    case "percent":
      return percent(value);
    case "compact":
      return compact(value).toUpperCase();
    case "number":
      return number(value);
    default:
      return number(value);
  }
}

import { scaleBand, scaleLinear, scalePoint } from "d3-scale";

/** Continuous numeric scale (thin wrapper over d3-scale). */
export function linearScale(
  domain: readonly [number, number],
  range: readonly [number, number]
): (value: number) => number {
  return scaleLinear().domain([...domain]).range([...range]);
}

/** Categorical position scale; categories land at discrete points across the range. */
export function pointScale(
  categories: readonly string[],
  range: readonly [number, number]
): (value: string) => number {
  const scale = scalePoint<string>()
    .domain([...categories])
    .range([...range])
    .padding(0);
  return (value: string) => scale(value) ?? 0;
}

/** A band scale: maps a category to its slot start, plus the slot geometry. */
export interface BandScale {
  (value: string): number;
  /** Width of each category's band (where bars are drawn). */
  bandwidth: number;
  /** Distance between adjacent band starts (bandwidth + padding). */
  step: number;
}

/** Categorical band scale for bars - each category gets a slot of `bandwidth`. */
export function bandScale(
  categories: readonly string[],
  range: readonly [number, number],
  padding = 0.2
): BandScale {
  const scale = scaleBand<string>()
    .domain([...categories])
    .range([...range])
    .padding(padding);
  const fn = ((value: string) => scale(value) ?? 0) as BandScale;
  fn.bandwidth = scale.bandwidth();
  fn.step = scale.step();
  return fn;
}

/** Round a raw maximum up to a readable axis bound (1-2-5 x 10^n). */
export function niceMax(rawMax: number): number {
  if (rawMax <= 0) return 1;
  const pow = Math.pow(10, Math.floor(Math.log10(rawMax)));
  const frac = rawMax / pow;
  const niceFrac = frac <= 1 ? 1 : frac <= 2 ? 2 : frac <= 5 ? 5 : 10;
  return niceFrac * pow;
}

import { area as d3Area, line as d3Line } from "d3-shape";

export interface XYPoint {
  x: number;
  y: number;
}

/** SVG `d` for a line through the given points. Empty string if no points. */
export function linePath(points: readonly XYPoint[]): string {
  const gen = d3Line<XYPoint>()
    .x((p) => p.x)
    .y((p) => p.y);
  return gen([...points]) ?? "";
}

/** SVG `d` for an area between the points and a horizontal baseline. */
export function areaPath(points: readonly XYPoint[], baseline: number): string {
  const gen = d3Area<XYPoint>()
    .x((p) => p.x)
    .y0(baseline)
    .y1((p) => p.y);
  return gen([...points]) ?? "";
}

/** A series registered with the chart context, contributing values to the shared Y domain. */
export interface SeriesReg {
  key: string;
  /** Live accessor - reads current data so the domain stays reactive. */
  values: () => readonly number[];
}

/** Shared Y domain [0, max] across all registered series. Falls back to [0, 1]. */
export function computeYDomain(
  registrations: readonly SeriesReg[]
): [number, number] {
  let max = 0;
  let seen = false;
  for (const reg of registrations) {
    for (const v of reg.values()) {
      seen = true;
      if (v > max) max = v;
    }
  }
  return [0, seen && max > 0 ? max : 1];
}

/** Center + radius for a radial chart inside a width x height box. */
export interface PolarLayout {
  cx: number;
  cy: number;
  radius: number;
}

/** Compute the center and a radius that fits the box, minus padding for labels. */
export function polarLayout(width: number, height: number, pad = 8): PolarLayout {
  return {
    cx: width / 2,
    cy: height / 2,
    radius: Math.max(0, Math.min(width, height) / 2 - pad),
  };
}

/** Cartesian point on a circle. Angle in radians, 0 at the top, clockwise. */
export function polarPoint(
  cx: number,
  cy: number,
  radius: number,
  angle: number
): { x: number; y: number } {
  return {
    x: cx + radius * Math.sin(angle),
    y: cy - radius * Math.cos(angle),
  };
}

/** Closed SVG polygon `d` through the given points. Empty string if < 2 points. */
export function polygonPath(
  points: readonly { x: number; y: number }[]
): string {
  if (points.length < 2) return "";
  return `M${points.map((p) => `${p.x},${p.y}`).join("L")}Z`;
}

import * as React from "react";
import { computeYDomain, type SeriesReg } from "./domain";
import { linearScale, niceMax, pointScale } from "./scales";
import { DEFAULT_MARGIN, type Datum, type Margin } from "./types";

/**
 * Reactive hub shared by a chart frame and its child series/axes via React Context.
 * The frame writes dimensions + data; series self-register their values so
 * the frame can compute a shared domain; scales are derived during render.
 *
 * Angular's `ChartContext` (signals + computed) is replaced here by:
 * - useState for the mutable cells (width, height, data, registry...)
 * - useMemo for the derived values (innerWidth, yDomain, xScale, ...)
 * - register/unregister callbacks exposed through context
 *
 * Series children call `useChart()` to read derived state and self-register
 * their values via useEffect.
 */
export interface ChartContextValue {
  width: number;
  height: number;
  margin: Margin;
  data: readonly Datum[];
  xKey: string;

  seriesKeys: readonly string[];

  innerWidth: number;
  innerHeight: number;
  plotLeft: number;
  plotRight: number;
  plotTop: number;
  plotBottom: number;

  yDomain: readonly [number, number];
  yScale: (v: number) => number;
  xScale: (v: string) => number;

  register: (reg: SeriesReg) => void;
  unregister: (key: string) => void;
}

const ChartContext = React.createContext<ChartContextValue | null>(null);

/** Read the chart context. Throws if used outside a ChartProvider. */
export function useChart(): ChartContextValue {
  const ctx = React.useContext(ChartContext);
  if (!ctx) {
    throw new Error(
      "useChart() must be used inside a <ChartProvider> (rendered by <ChartFrame>)."
    );
  }
  return ctx;
}

export interface ChartProviderProps {
  width: number;
  height: number;
  margin?: Margin;
  data: readonly Datum[];
  xKey: string;
  children?: React.ReactNode;
}

/**
 * Provides the ChartContext to all descendants. Renders no DOM of its own -
 * children are returned as-is (the parent `<svg>` of ChartFrame owns the
 * actual mount).
 */
export function ChartProvider({
  width,
  height,
  margin = DEFAULT_MARGIN,
  data,
  xKey,
  children,
}: ChartProviderProps) {
  // Registry of series contributing to the shared Y domain. We use a ref +
  // a version counter so register/unregister are stable callbacks but still
  // trigger a re-render when the set of series changes.
  const registryRef = React.useRef<SeriesReg[]>([]);
  const [, bump] = React.useReducer((x: number) => x + 1, 0);

  const register = React.useCallback((reg: SeriesReg) => {
    const prev = registryRef.current;
    registryRef.current = [...prev.filter((s) => s.key !== reg.key), reg];
    bump();
  }, []);

  const unregister = React.useCallback((key: string) => {
    registryRef.current = registryRef.current.filter((s) => s.key !== key);
    bump();
  }, []);

  const seriesKeys = React.useMemo(
    () => registryRef.current.map((s) => s.key),
    [registryRef.current.length, registryRef.current]
  );

  const innerWidth = Math.max(0, width - margin.left - margin.right);
  const innerHeight = Math.max(0, height - margin.top - margin.bottom);

  // Plot bounds in absolute SVG coordinates. Scales map into these so the
  // margins become real gutters (Y labels on the left, X labels below).
  const plotLeft = margin.left;
  const plotRight = Math.max(margin.left, width - margin.right);
  const plotTop = margin.top;
  const plotBottom = Math.max(margin.top, height - margin.bottom);

  const yDomain = React.useMemo<readonly [number, number]>(() => {
    const [min, rawMax] = computeYDomain(registryRef.current);
    return [min, niceMax(rawMax)];
  }, [seriesKeys, data]);

  const yScale = React.useMemo(
    () => linearScale(yDomain, [plotBottom, plotTop]),
    [yDomain, plotBottom, plotTop]
  );

  const xScale = React.useMemo(
    () =>
      pointScale(
        data.map((d) => String(d[xKey])),
        [plotLeft, plotRight]
      ),
    [data, xKey, plotLeft, plotRight]
  );

  const value = React.useMemo<ChartContextValue>(
    () => ({
      width,
      height,
      margin,
      data,
      xKey,
      seriesKeys,
      innerWidth,
      innerHeight,
      plotLeft,
      plotRight,
      plotTop,
      plotBottom,
      yDomain,
      yScale,
      xScale,
      register,
      unregister,
    }),
    [
      width,
      height,
      margin,
      data,
      xKey,
      seriesKeys,
      innerWidth,
      innerHeight,
      plotLeft,
      plotRight,
      plotTop,
      plotBottom,
      yDomain,
      yScale,
      xScale,
      register,
      unregister,
    ]
  );

  return (
    <ChartContext.Provider value={value}>{children}</ChartContext.Provider>
  );
}

import * as React from "react";
import { ChartProvider } from "./chart-context";
import { DEFAULT_MARGIN, type Datum, type Margin } from "./types";

export interface ChartFrameProps
  extends Omit<React.SVGProps<SVGSVGElement>, "data" | "viewBox"> {
  data: readonly Datum[];
  xKey: string;
  margin?: Margin;
  children?: React.ReactNode;
}

/**
 * Root of a headless chart. Renders an `<svg>`, owns the size via
 * ResizeObserver (client-only), and wraps children in a `ChartProvider`
 * so series/axes can read scales, domains, and registered series.
 *
 * @example
 * ```tsx
 * <ChartFrame data={data} xKey="month" className="aspect-video w-full">
 *   <Area dataKey="sales" />
 * </ChartFrame>
 * ```
 */
export function ChartFrame({
  data,
  xKey,
  margin = DEFAULT_MARGIN,
  children,
  ...svgProps
}: ChartFrameProps) {
  const svgRef = React.useRef<SVGSVGElement | null>(null);
  const [size, setSize] = React.useState<{ width: number; height: number }>({
    width: 0,
    height: 0,
  });

  React.useEffect(() => {
    const node = svgRef.current;
    if (!node) return;
    if (typeof ResizeObserver === "undefined") {
      const rect = node.getBoundingClientRect();
      setSize({ width: rect.width, height: rect.height });
      return;
    }
    const ro = new ResizeObserver((entries) => {
      const box = entries[0]?.contentRect;
      if (box) {
        setSize({ width: box.width, height: box.height });
      }
    });
    ro.observe(node);
    return () => ro.disconnect();
  }, []);

  return (
    <svg
      ref={svgRef}
      data-slot="chart-frame"
      preserveAspectRatio="none"
      viewBox={`0 0 ${size.width} ${size.height}`}
      {...svgProps}
    >
      <ChartProvider
        width={size.width}
        height={size.height}
        margin={margin}
        data={data}
        xKey={xKey}
      >
        {children}
      </ChartProvider>
    </svg>
  );
}

import * as React from "react";
import { useChart } from "./chart-context";
import { formatValue } from "./format";

/** Pure: `count` evenly spaced tick values from 0..max inclusive. */
export function computeTicks(max: number, count: number): number[] {
  if (max <= 0 || count <= 0) return [0];
  const step = max / count;
  return Array.from({ length: count + 1 }, (_, i) =>
    Math.round(i * step * 1e6) / 1e6
  );
}

export interface YTick {
  value: number;
  y: number;
  label: string;
}

export interface XTick {
  label: string;
  x: number;
}

export interface YAxisGeometry {
  ticks: YTick[];
  labelX: number;
}

export interface XAxisGeometry {
  ticks: XTick[];
  labelY: number;
}

/** Hook: Y axis ticks + pixel Y + formatted label, read from the context. */
export function useYAxis(count = 4, format = ""): YAxisGeometry {
  const ctx = useChart();
  const labelX = Math.max(0, ctx.plotLeft - 6);
  const [, max] = ctx.yDomain;
  const y = ctx.yScale;
  const ticks = computeTicks(max, count).map((value) => ({
    value,
    y: y(value),
    label: formatValue(value, format || "number"),
  }));
  return { ticks, labelX };
}

/** Hook: X axis tick positions + category labels, read from the context. */
export function useXAxis(): XAxisGeometry {
  const ctx = useChart();
  const labelY = ctx.plotBottom + 16;
  const x = ctx.xScale;
  const ticks = ctx.data
    .map((d) => String(d[ctx.xKey]))
    .map((label) => ({ label, x: x(label) }));
  return { ticks, labelY };
}

export interface YAxisProps {
  count?: number;
  format?: string;
  children?: (geom: YAxisGeometry) => React.ReactNode;
}

export interface XAxisProps {
  children?: (geom: XAxisGeometry) => React.ReactNode;
}

/** Component variant of useYAxis. Renders a `<g>` and calls `children(geom)`. */
export function YAxis({ count = 4, format = "", children }: YAxisProps) {
  const geom = useYAxis(count, format);
  return <g data-slot="y-axis">{children ? children(geom) : null}</g>;
}

/** Component variant of useXAxis. Renders a `<g>` and calls `children(geom)`. */
export function XAxis({ children }: XAxisProps) {
  const geom = useXAxis();
  return <g data-slot="x-axis">{children ? children(geom) : null}</g>;
}

import * as React from "react";
import { useChart } from "./chart-context";
import { computeTicks } from "./axis";

export interface GridLine {
  y: number;
  x1: number;
  x2: number;
}

/** Hook: horizontal gridlines aligned to the Y ticks. */
export function useCartesianGrid(count = 4): GridLine[] {
  const ctx = useChart();
  const [, max] = ctx.yDomain;
  const y = ctx.yScale;
  const x1 = ctx.plotLeft;
  const x2 = ctx.plotRight;
  return computeTicks(max, count).map((value) => ({ y: y(value), x1, x2 }));
}

export interface CartesianGridProps {
  count?: number;
  children?: (lines: GridLine[]) => React.ReactNode;
}

/**
 * Component variant of useCartesianGrid. Renders a `<g>` and exposes the
 * grid `lines` so the styled layer can draw them (the headless layer stays
 * visual-free).
 */
export function CartesianGrid({ count = 4, children }: CartesianGridProps) {
  const lines = useCartesianGrid(count);
  return (
    <g data-slot="cartesian-grid">{children ? children(lines) : null}</g>
  );
}

import * as React from "react";
import { useChart } from "./chart-context";
import { areaPath } from "./shape";
import type { Datum } from "./types";

/** Pure: project data through the scales into an area `d` string. */
export function computeAreaPath(
  data: readonly Datum[],
  xKey: string,
  yKey: string,
  xScale: (v: string) => number,
  yScale: (v: number) => number,
  baseline: number
): string {
  if (data.length === 0) return "";
  const points = data.map((d) => ({
    x: xScale(String(d[xKey])),
    y: yScale(Number(d[yKey])),
  }));
  return areaPath(points, baseline);
}

export interface AreaProps
  extends Omit<React.SVGProps<SVGPathElement>, "fill" | "d"> {
  /** Data field this area represents. */
  dataKey: string;
  color?: string;
  fillOpacity?: number;
}

/**
 * Renders a filled area for one series on a `<path>` inside a `<ChartFrame>`.
 * Self-registers its values so the frame's shared Y domain includes this series.
 *
 * @example `<Area dataKey="sales" color="var(--chart-1)" />`
 */
export function Area({
  dataKey,
  color = "currentColor",
  fillOpacity = 0.25,
  ...pathProps
}: AreaProps) {
  const ctx = useChart();
  const { register, unregister, data: ctxData } = ctx;

  // Self-register values for the shared Y domain. We register before paint
  // so the domain is correct on first render. See bar.tsx for why ctx must
  // NOT be in the effect deps - it causes register/unregister to loop.
  const dataRef = React.useRef(ctxData);
  React.useEffect(() => {
    dataRef.current = ctxData;
  });

  React.useEffect(() => {
    register({
      key: dataKey,
      values: () => dataRef.current.map((row) => Number(row[dataKey])),
    });
    return () => unregister(dataKey);
  }, [dataKey, register, unregister]);

  const d = computeAreaPath(
    ctx.data,
    ctx.xKey,
    dataKey,
    ctx.xScale,
    ctx.yScale,
    ctx.yScale(0)
  );

  return (
    <path
      data-slot="area"
      d={d}
      fill={color}
      fillOpacity={fillOpacity}
      {...pathProps}
    />
  );
}

import * as React from "react";
import { useChart } from "./chart-context";
import { linePath } from "./shape";
import type { Datum } from "./types";

/** Pure: project data through the scales into a line `d` string. */
export function computeLinePath(
  data: readonly Datum[],
  xKey: string,
  yKey: string,
  xScale: (v: string) => number,
  yScale: (v: number) => number
): string {
  if (data.length === 0) return "";
  return linePath(
    data.map((d) => ({
      x: xScale(String(d[xKey])),
      y: yScale(Number(d[yKey])),
    }))
  );
}

export interface LineProps
  extends Omit<React.SVGProps<SVGPathElement>, "stroke" | "d" | "fill"> {
  dataKey: string;
  color?: string;
}

/**
 * Renders a stroked line for one series on a `<path>` inside a `<ChartFrame>`.
 * Self-registers its values so the frame's shared Y domain includes this series.
 *
 * @example `<Line dataKey="sales" color="var(--chart-1)" />`
 */
export function Line({
  dataKey,
  color = "currentColor",
  ...pathProps
}: LineProps) {
  const ctx = useChart();
  const { register, unregister, data: ctxData } = ctx;

  // See bar.tsx for the full explanation: depending on `ctx` here loops
  // forever (register -> bump -> new ctx -> effect re-runs -> unregister
  // -> bump -> ...). Capture data in a ref and depend only on the stable
  // register/unregister callbacks plus dataKey.
  const dataRef = React.useRef(ctxData);
  React.useEffect(() => {
    dataRef.current = ctxData;
  });

  React.useEffect(() => {
    register({
      key: dataKey,
      values: () => dataRef.current.map((row) => Number(row[dataKey])),
    });
    return () => unregister(dataKey);
  }, [dataKey, register, unregister]);

  const d = computeLinePath(ctx.data, ctx.xKey, dataKey, ctx.xScale, ctx.yScale);

  return (
    <path
      data-slot="line"
      fill="none"
      d={d}
      stroke={color}
      {...pathProps}
    />
  );
}

import * as React from "react";
import { useChart } from "./chart-context";
import { bandScale } from "./scales";

export interface BarRect {
  x: number;
  y: number;
  width: number;
  height: number;
}

/**
 * Hook variant: register a bar series and return its rects. The styled
 * layer renders the `<rect>` elements - the hook only computes geometry.
 * Self-registers values for the shared domain and positions sub-bars by
 * series index so multiple series sit side-by-side within each category.
 */
export function useBar(dataKey: string): BarRect[] {
  const ctx = useChart();
  const { register, unregister, data: ctxData } = ctx;

  // Capture latest data in a ref so the registered `values` callback always
  // reads fresh data without forcing the effect to re-run on every render.
  // ctx is a fresh object identity each render (useMemo deps include
  // scales/domain), so depending on it here caused register/unregister to
  // loop: register -> bump() in provider -> new ctx -> effect runs again ->
  // cleanup unregister -> bump() -> infinite "Maximum update depth" loop.
  const dataRef = React.useRef(ctxData);
  React.useEffect(() => {
    dataRef.current = ctxData;
  });

  React.useEffect(() => {
    register({
      key: dataKey,
      values: () => dataRef.current.map((row) => Number(row[dataKey])),
    });
    return () => unregister(dataKey);
  }, [dataKey, register, unregister]);

  const data = ctx.data;
  const xKey = ctx.xKey;
  const categories = data.map((d) => String(d[xKey]));
  const band = bandScale(
    categories,
    [ctx.plotLeft, ctx.plotRight],
    0.2
  );
  const keys = ctx.seriesKeys;
  const count = Math.max(1, keys.length);
  const index = Math.max(0, keys.indexOf(dataKey));
  const subWidth = band.bandwidth / count;
  const baseline = ctx.yScale(0);
  const yScale = ctx.yScale;

  return data.map((d) => {
    const value = yScale(Number(d[dataKey]));
    return {
      x: band(String(d[xKey])) + subWidth * index,
      y: value,
      width: Math.max(0, subWidth - 1),
      height: Math.max(0, baseline - value),
    };
  });
}

export interface BarProps {
  dataKey: string;
  color?: string;
  /** Render each `<rect>` for this series. */
  children?: (rects: BarRect[]) => React.ReactNode;
}

/**
 * Component variant of useBar. Renders a `<g>` and calls `children(rects)`
 * with the computed bar geometry. Useful when the styled layer wants to keep
 * a JSX-only composition style.
 *
 * @example
 * ```tsx
 * <Bar dataKey="sales">
 *   {(rects) => rects.map((r, i) => <rect key={i} {...r} fill="..." />)}
 * </Bar>
 * ```
 */
export function Bar({ dataKey, children }: BarProps) {
  const rects = useBar(dataKey);
  return <g data-slot="bar">{children ? children(rects) : null}</g>;
}

import * as React from "react";
import { useChart } from "./chart-context";
import { linearScale } from "./scales";

export interface ScatterPoint {
  cx: number;
  cy: number;
}

export interface ScatterXTick {
  x: number;
  label: string;
}

export interface ScatterGeometry {
  points: ScatterPoint[];
  xTicks: ScatterXTick[];
  labelY: number;
}

/**
 * Hook variant: register a scatter series and return its points, X tick
 * positions, and a Y baseline for tick labels.
 *
 * X uses a linear scale over the data's X extent; Y uses the shared scale.
 * Self-registers Y values for the shared domain.
 */
export function useScatter(dataKey: string): ScatterGeometry {
  const ctx = useChart();
  const { register, unregister, data: ctxData } = ctx;

  // See bar.tsx: ctx in deps causes infinite register/unregister loop.
  const dataRef = React.useRef(ctxData);
  React.useEffect(() => {
    dataRef.current = ctxData;
  });

  React.useEffect(() => {
    register({
      key: dataKey,
      values: () => dataRef.current.map((row) => Number(row[dataKey])),
    });
    return () => unregister(dataKey);
  }, [dataKey, register, unregister]);

  const xs = ctx.data.map((d) => Number(d[ctx.xKey]));
  const lo = xs.length ? Math.min(...xs) : 0;
  const hi = xs.length ? Math.max(...xs) : 1;
  const xScale = linearScale(lo === hi ? [lo, lo + 1] : [lo, hi], [
    ctx.plotLeft,
    ctx.plotRight,
  ]);

  const yScale = ctx.yScale;
  const points: ScatterPoint[] = ctx.data.map((d) => ({
    cx: xScale(Number(d[ctx.xKey])),
    cy: yScale(Number(d[dataKey])),
  }));

  let xTicks: ScatterXTick[] = [];
  if (xs.length > 0) {
    const values = lo === hi ? [lo] : [lo, (lo + hi) / 2, hi];
    xTicks = values.map((v) => ({ x: xScale(v), label: String(Math.round(v)) }));
  }

  const labelY = ctx.plotBottom + 16;

  return { points, xTicks, labelY };
}

export interface ScatterProps {
  dataKey: string;
  color?: string;
  /** Render geometry for this series. */
  children?: (geom: ScatterGeometry) => React.ReactNode;
}

/**
 * Component variant of useScatter. Renders a `<g>` and calls
 * `children(geometry)` with the computed points and X ticks.
 *
 * @example
 * ```tsx
 * <Scatter dataKey="score">
 *   {({ points }) => points.map((p, i) => <circle key={i} cx={p.cx} cy={p.cy} r={4} />)}
 * </Scatter>
 * ```
 */
export function Scatter({ dataKey, children }: ScatterProps) {
  const geom = useScatter(dataKey);
  return <g data-slot="scatter">{children ? children(geom) : null}</g>;
}

import * as React from "react";
import { arc as d3Arc, pie as d3Pie, type PieArcDatum } from "d3-shape";
import { useChart } from "./chart-context";
import { polarLayout } from "./polar";

export interface PieSlice {
  d: string;
  index: number;
  name: string;
  value: number;
}

export interface PieGeometry {
  slices: PieSlice[];
  transform: string;
}

/**
 * Hook: compute pie/donut slices.
 *
 * Slice value comes from `valueKey`; slice name from the frame's `xKey`.
 * Set `innerRadiusRatio` > 0 for a donut. Apply the returned `transform`
 * to the host `<g>` so the pie is centered.
 */
export function usePie(valueKey: string, innerRadiusRatio = 0): PieGeometry {
  const ctx = useChart();

  const layout = polarLayout(ctx.width, ctx.height, 8);
  const transform = `translate(${layout.cx},${layout.cy})`;

  const data = ctx.data;
  const nameKey = ctx.xKey;
  const values = data.map((d) => Number(d[valueKey]));
  const arcs = d3Pie<number>().sort(null)(values);
  const radius = layout.radius;
  const gen = d3Arc<PieArcDatum<number>>()
    .innerRadius(radius * innerRadiusRatio)
    .outerRadius(radius);

  const slices: PieSlice[] = arcs.map((a, i) => ({
    d: gen(a) ?? "",
    index: i,
    name: String(data[i]?.[nameKey] ?? ""),
    value: values[i],
  }));

  return { slices, transform };
}

export interface PieProps {
  /** Numeric field for slice values. */
  valueKey: string;
  /** 0 = full pie; e.g. 0.6 = donut with a hole at 60% of the radius. */
  innerRadiusRatio?: number;
  /** Render slices. */
  children?: (geom: PieGeometry) => React.ReactNode;
}

/**
 * Component variant of usePie. Renders a `<g>` translated to the pie center
 * and calls `children(geometry)` with slices ready to render as `<path>`s.
 */
export function Pie({ valueKey, innerRadiusRatio = 0, children }: PieProps) {
  const geom = usePie(valueKey, innerRadiusRatio);
  return (
    <g data-slot="pie" transform={geom.transform}>
      {children ? children(geom) : null}
    </g>
  );
}

import * as React from "react";
import { useChart } from "./chart-context";
import { polarLayout, polarPoint, polygonPath } from "./polar";

export interface RadarAxis {
  x2: number;
  y2: number;
  label: string;
  lx: number;
  ly: number;
}

export interface RadarGeometry {
  d: string;
  axes: RadarAxis[];
  rings: string[];
  center: { cx: number; cy: number; radius: number };
}

/**
 * Hook: register a radar series and return its polygon `d` plus shared
 * axes / rings (the same for every series in the same frame).
 *
 * Categories radiate as spokes (one per data row, by the frame's `xKey`);
 * the value maps to distance along each spoke. Self-registers values so
 * all series share the same radial max.
 */
export function useRadar(dataKey: string): RadarGeometry {
  const ctx = useChart();
  const { register, unregister, data: ctxData } = ctx;

  // See bar.tsx: ctx in deps causes infinite register/unregister loop.
  const dataRef = React.useRef(ctxData);
  React.useEffect(() => {
    dataRef.current = ctxData;
  });

  React.useEffect(() => {
    register({
      key: dataKey,
      values: () => dataRef.current.map((row) => Number(row[dataKey])),
    });
    return () => unregister(dataKey);
  }, [dataKey, register, unregister]);

  const layout = polarLayout(ctx.width, ctx.height, 28);
  const data = ctx.data;
  const n = data.length;
  const [, max] = ctx.yDomain;

  let d = "";
  if (n > 0) {
    const points = data.map((row, i) => {
      const angle = (i / n) * 2 * Math.PI;
      const r = (Number(row[dataKey]) / max) * layout.radius;
      return polarPoint(layout.cx, layout.cy, r, angle);
    });
    d = polygonPath(points);
  }

  const axes: RadarAxis[] = data.map((row, i) => {
    const angle = (i / n) * 2 * Math.PI;
    const end = polarPoint(layout.cx, layout.cy, layout.radius, angle);
    const label = polarPoint(layout.cx, layout.cy, layout.radius + 14, angle);
    return {
      x2: end.x,
      y2: end.y,
      label: String(row[ctx.xKey]),
      lx: label.x,
      ly: label.y,
    };
  });

  const rings: string[] =
    n === 0
      ? []
      : [0.25, 0.5, 0.75, 1].map((level) =>
          polygonPath(
            data.map((_, i) =>
              polarPoint(
                layout.cx,
                layout.cy,
                layout.radius * level,
                (i / n) * 2 * Math.PI
              )
            )
          )
        );

  return {
    d,
    axes,
    rings,
    center: { cx: layout.cx, cy: layout.cy, radius: layout.radius },
  };
}

export interface RadarProps {
  dataKey: string;
  color?: string;
  children?: (geom: RadarGeometry) => React.ReactNode;
}

/**
 * Component variant of useRadar. Renders a `<g>` and calls `children(geometry)`.
 */
export function Radar({ dataKey, children }: RadarProps) {
  const geom = useRadar(dataKey);
  return <g data-slot="radar">{children ? children(geom) : null}</g>;
}

import * as React from "react";
import { arc as d3Arc } from "d3-shape";
import { useChart } from "./chart-context";
import { polarLayout } from "./polar";

export interface RadialArc {
  /** Value arc (sweep proportional to the value). */
  d: string;
  /** Full-circle track behind the value arc. */
  track: string;
  index: number;
  name: string;
  value: number;
}

export interface RadialBarGeometry {
  arcs: RadialArc[];
  transform: string;
}

interface ArcInput {
  innerRadius: number;
  outerRadius: number;
  startAngle: number;
  endAngle: number;
}

/**
 * Hook: compute concentric radial bars - one ring per data row, sweep
 * proportional to its `valueKey` value (relative to the largest value).
 * Apply the returned `transform` to center the host `<g>`.
 */
export function useRadialBar(valueKey: string): RadialBarGeometry {
  const ctx = useChart();

  const layout = polarLayout(ctx.width, ctx.height, 8);
  const transform = `translate(${layout.cx},${layout.cy})`;

  const data = ctx.data;
  const n = data.length;
  if (n === 0) {
    return { arcs: [], transform };
  }

  const nameKey = ctx.xKey;
  const values = data.map((d) => Number(d[valueKey]));
  const max = Math.max(...values, 1);
  const { radius } = layout;
  const band = radius / (n + 0.5);
  const gen = d3Arc<ArcInput>().cornerRadius(band * 0.35);

  const arcs: RadialArc[] = data.map((row, i) => {
    const outer = radius - band * i;
    const inner = outer - band * 0.7;
    const endAngle = (values[i] / max) * 2 * Math.PI;
    const base = { innerRadius: inner, outerRadius: outer, startAngle: 0 };
    return {
      d: gen({ ...base, endAngle }) ?? "",
      track: gen({ ...base, endAngle: 2 * Math.PI }) ?? "",
      index: i,
      name: String(row[nameKey]),
      value: values[i],
    };
  });

  return { arcs, transform };
}

export interface RadialBarProps {
  valueKey: string;
  children?: (geom: RadialBarGeometry) => React.ReactNode;
}

/**
 * Component variant of useRadialBar. Renders a `<g>` translated to the
 * chart center and calls `children(geometry)` with the arc paths.
 */
export function RadialBar({ valueKey, children }: RadialBarProps) {
  const geom = useRadialBar(valueKey);
  return (
    <g data-slot="radial-bar" transform={geom.transform}>
      {children ? children(geom) : null}
    </g>
  );
}

